/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // Disjoint Set Union (DSU) structure
    // parent[i]: parent of node i
    // parity[i]: the parity of the path weight from node i to its set representative (parent[i])
    const parent = Array(n).fill(0).map((_, i) => i);
    // parity[i] stores the XOR sum (parity) of edge weights on the path from i to parent[i].
    // 0 for even, 1 for odd.
    const parity = Array(n).fill(0);

    // Find operation with path compression and parity update
    function find(i) {
        if (parent[i] === i) {
            return i;
        }
        const root = find(parent[i]);
        // Update parity[i]: New parity is (old parity[i] XOR parity[parent[i]] before compression)
        // The path from i to root is (i -> parent[i]) + (parent[i] -> root)
        parity[i] = parity[i] ^ parity[parent[i]];
        parent[i] = root;
        return root;
    }

    let addedEdgesCount = 0;

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const w = edge[2]; // w is 0 or 1

        const rootU = find(u);
        const rootV = find(v);

        if (rootU !== rootV) {
            // If u and v are in different components, adding the edge will not form a cycle.
            // We add the edge and perform union.
            addedEdgesCount++;

            // Union by setting rootU's parent to rootV (arbitrarily)
            parent[rootU] = rootV;

            // Update parity[rootU]:
            // We want the parity from rootU to rootV to be the weight w.
            // Path: rootU -> u -> v -> rootV
            // Parity(rootU -> rootV) = Parity(rootU -> u) XOR w XOR Parity(v -> rootV)
            // Parity(rootU -> u) = parity[u] (since u's root is now rootU, but before union, path was u -> rootU)
            // Parity(u -> rootU) is parity[u]. So Parity(rootU -> u) is parity[u].
            // Parity(v -> rootV) is parity[v].
            // The required parity for the new edge (rootU -> rootV) is:
            // parity[rootU] = parity[u] ^ w ^ parity[v]
            parity[rootU] = parity[u] ^ w ^ parity[v];

        } else {
            // If u and v are in the same component, adding the edge creates a cycle.
            // We must check if the cycle's total weight is even.

            // Cycle path: u -> ... -> rootU -> ... -> v -> u (new edge)
            // Path u to v through tree edges has parity: parity[u] ^ parity[v]
            // Cycle weight parity = (Parity of tree path u to v) XOR w
            // Cycle weight parity = (parity[u] ^ parity[v]) ^ w

            const cycleParity = parity[u] ^ parity[v] ^ w;

            // If cycleParity is 0 (even), we add the edge.
            if (cycleParity === 0) {
                addedEdgesCount++;
                // In DSU terms, when the roots are the same, we don't change the structure,
                // but we must update the parity information for consistency if we were to use 
                // this edge in future calculations involving path weights.
                // However, since we only care about connectivity and parity checks, 
                // and the edge weight 'w' is effectively '0' in terms of connectivity structure,
                // we only need to ensure future find operations reflect the new path weight.

                // If we add the edge, the path weight between u and v effectively changes 
                // from being defined by the tree path (parity[u]^parity[v]) to potentially 
                // using the new edge (w). For future operations involving u or v, 
                // we essentially add w to the existing parity difference.
                // Since find(u) and find(v) already compressed paths to the same root, 
                // we only need to update the parity of one node relative to the other 
                // if we want the DSU state to reflect the new cycle property.
                // A simpler way for this problem context is to observe that if we add an 
                // edge forming an even cycle, the property of all cycles remaining even holds.
                // The DSU structure itself doesn't need explicit modification beyond the count.
                // The path parity relationship between u and v remains consistent with the 
                // current root structure if we assume the new edge is part of the graph.
                // Since we are not querying path weights *after* addition, simply incrementing 
                // the count is sufficient if the condition is met.
            }
        }
    }

    return addedEdgesCount;
}

